fn parse_external_entity_decl(line: &str) -> Option<(String, String)> {
    let mut s = line.trim();

    if !s.starts_with("<!ENTITY") {
        return None;
    }

    s = s.trim_start_matches("<!ENTITY").trim();
    let mut parts = s.split_whitespace();
    let name = parts.next()?.to_string();

    let system_pos = s.find("SYSTEM")?;
    let after_system = s[system_pos + "SYSTEM".len()..].trim();

    let quote = if after_system.starts_with('"') {
        '"'
    } else if after_system.starts_with('\'') {
        '\''
    } else {
        return None;
    };

    let rest = &after_system[1..];
    let end = rest.find(quote)?;
    let path = rest[..end].to_string();

    Some((name, path))
}

